config_walkthrough.code:
terraform {
  required_version = ">= 1.5"

  backend "gcs" {
    bucket  = "landing-zone-tfstate-prod-us-central1"
    prefix  = "envs/core/v1"
    impersonate_service_account = "terraform-apply-sa@landing-zone-core.iam.gserviceaccount.com"
  }

  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
    google-beta = {
      source  = "hashicorp/google-beta"
      version = "~> 5.0"
    }
  }
}

resource "google_iam_workload_identity_pool" "gh_actions" {
  workload_identity_pool_id = "github-actions"
  display_name              = "GitHub Actions CI"
}

resource "google_iam_workload_identity_pool_provider" "github" {
  workload_identity_pool_id          = google_iam_workload_identity_pool.gh_actions.workload_identity_pool_id
  workload_identity_pool_provider_id = "github"
  oidc { issuer_uri = "https://token.actions.githubusercontent.com" }

  # CRITICAL: scope to a specific repo to prevent any GitHub Actions
  # run in any repo from impersonating the landing-zone apply SA.
  attribute_condition = "attribute.repository == 'richmuscle/terraform-gcp-landing-zone'"

  attribute_mapping = {
    "google.subject"       = "assertion.sub"
    "attribute.repository" = "assertion.repository"
    "attribute.ref"        = "assertion.ref"
  }
}
